using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // Preserve EF Core 8 discriminator property name (EF 9 defaults to "$type").
            // Required: existing 500K documents use "Discriminator" and direct SQL queries reference c.Discriminator.
            entity.HasDiscriminator<string>("Discriminator");

            // Preserve EF Core 8 compound id format "Product|123" (EF 9 defaults to key-only "123").
            // Required: existing documents were written with the old format.
            entity.HasRootDiscriminatorInJsonId(true);
        });

        // REMOVED: HasIndex — EF Core 9 Cosmos provider throws at startup.
        // Manage indexing policy via Azure Portal, Bicep, or Terraform instead.
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

